architect_service_code = """
const { spawn } = require('child_process');
const path = require('path');
const pool = require('../db/pool'); // Assuming this is where the pool is

class ArchitectService {
    static async analyzeUrl(projectId, url) {
        return new Promise((resolve, reject) => {
            const pythonProcess = spawn('python3', [
                path.join(__dirname, '../../voodoo_architect/scraper/scraper.py'),
                url
            ]);

            let data = '';
            pythonProcess.stdout.on('data', (chunk) => { data += chunk; });
            pythonProcess.stderr.on('data', (chunk) => { console.error(`Python Error: ${chunk}`); });

            pythonProcess.on('close', async (code) => {
                if (code !== 0) return reject(new Error(`Scraper exited with code ${code}`));
                try {
                    const componentMap = JSON.parse(data);
                    await pool.query(
                        'UPDATE architect_projects SET component_map = $1, status = $2 WHERE id = $3',
                        [JSON.stringify(componentMap), 'generated', projectId]
                    );
                    resolve(componentMap);
                } catch (e) {
                    reject(new Error('Failed to parse scraper output'));
                }
            });
        });
    }

    static async generateSite(projectId, brandProfile) {
        return new Promise((resolve, reject) => {
            const pythonProcess = spawn('python3', [
                path.join(__dirname, '../../voodoo_architect/generator/generator.py'),
                JSON.stringify(brandProfile)
            ]);

            let data = '';
            pythonProcess.stdout.on('data', (chunk) => { data += chunk; });
            pythonProcess.stderr.on('data', (chunk) => { console.error(`Python Error: ${chunk}`); });

            pythonProcess.on('close', async (code) => {
                if (code !== 0) return reject(new Error(`Generator exited with code ${code}`));
                try {
                    const generatedCode = data; // The .tsx content
                    await pool.query(
                        'UPDATE architect_projects SET generated_code = $1, revision_count = revision_count + 1 WHERE id = $2',
                        [generatedCode, projectId]
                    );
                    resolve(generatedCode);
                } catch (e) {
                    reject(new Error('Failed to save generated code'));
                }
            });
        });
    }
}

module.exports = ArchitectService;
