# The "Bob the Builder" Deployment Logic
# We need to implement a real FTP upload in the ArchitectService

deployment_logic = """
const ftp = require('basic-ftp');
const fs = require('fs');
const path = require('path');

class DeploymentService {
    static async deployToBob(projectId, code) {
        const client = new ftp.Client();
        try {
            await client.access({
                host: 'ftp.us.stackcp.com',
                user: 'bob@superhostagent.com',
                password: 'Bob1234$$',
                secure: false // StackCP usually uses standard FTP or explicit TLS
            });

            // Ensure root directory exists
            await client.ensureDir('/bob');

            // Create a unique folder for this project deployment
            const projectFolder = `/bob/${projectId}`;
            await client.ensureDir(projectFolder);

            // Write the generated code to a file locally first
            const localPath = path.join(__dirname, `../../tmp/site_${projectId}.html`);
            fs.writeFileSync(localPath, code);

            // Upload to FTP
            await client.uploadFrom(localPath, `${projectFolder}/index.html`);

            // Clean up local file
            fs.unlinkSync(localPath);

            return `https://superhostagent.com/bob/${projectId}/index.html`;
        } catch (err) {
            console.error('FTP Deploy Error:', err);
            throw new Error(`Deployment failed: ${err.message}`);
        } finally {
            client.close();
        }
    }
}

module.exports = DeploymentService;
"""

